class Playground {
    async run(inputs) {
        const arrVals = inputs[0].split(',').map(Number);
        const k = parseInt(inputs[1]);

        if (!arrVals || arrVals.length === 0 || k <= 0 || k > arrVals.length) {
            this.log('Invalid input. Please provide a valid array and a positive window size k <= array length.');
            return null;
        }

        await this.arr.init(arrVals);
        await this.current_window_sum.put('sum', 0);
        await this.max_sum.put('max_sum', -Infinity);

        let windowStart = 0;
        let windowSum = 0;

        for (let windowEnd = 0; windowEnd < arrVals.length; windowEnd++) {
            const currentElement = arrVals[windowEnd];
            windowSum += currentElement;

            // Highlight the current element being added to the window
            this.log(`Adding element ${currentElement} at index ${windowEnd} to the window.`);
            await this.arr.highlight(windowEnd, '#ffb703'); // Orange for current element
            await this.await();

            // Once we have reached the window size 'k'
            if (windowEnd >= k - 1) {
                this.log(`Window size reached: [${windowStart} to ${windowEnd}]`);
                await this.current_window_sum.put('sum', windowSum);
                await this.max_sum.put('max_sum', Math.max(this.max_sum.getEntries()[0][1], windowSum));
                await this.await();

                // Highlight the current window
                await this.arr.highlightRange(windowStart, windowEnd, '#00e0ff'); // Blue for current window
                await this.await();

                // Slide the window: subtract the element going out
                const elementLeaving = arrVals[windowStart];
                windowSum -= elementLeaving;
                this.log(`Sliding window. Subtracting element ${elementLeaving} at index ${windowStart}.`);
                await this.arr.highlight(windowStart, '#f08080'); // Light red for element leaving
                await this.await();
                await this.arr.highlightRange(windowStart, windowEnd, '#00e0ff'); // Keep current window highlighted
                await this.await();
                await this.arr.highlight(windowStart, '#00f5a0'); // Green for element no longer in window
                await this.await();

                windowStart++;
                await this.current_window_sum.put('sum', windowSum);
                await this.max_sum.put('max_sum', Math.max(this.max_sum.getEntries()[0][1], windowSum));
                await this.await();
            }

            // Reset highlight for the element that was just added
            await this.arr.highlight(windowEnd, '#00f5a0'); // Green for visited/processed
            await this.await();
        }

        this.log('Finished traversing the array.');
        await this.arr.highlightRange(0, arrVals.length - 1, '#cccccc'); // Light gray for all processed
        await this.await();

        const finalMaxSum = this.max_sum.getEntries()[0][1];
        this.log(`The maximum sum of a subarray of size ${k} is: ${finalMaxSum}`);
        return finalMaxSum;
    }
}
